('cmp0qlowr00x0tux4bks7v5xp', '30% descuento – OPTICAS JUBILADOS (Selecta)', 'OPTICAS JUBILADOS | Otros Beneficios', FALSE, NULL, FALSE, NULL, '2026-03-04T00:00:00.000Z', '2026-06-30T00:00:00.000Z', 8, NULL, NULL, NULL, 'cmoi0k60i0000r7p8zyye0rfa', 'cmp0fje5700wsy7ambtapuadk', 'ACTIVE', 'https://www.macro.com.ar/beneficios?d=Any#41430TD0', NULL, NULL, '2026-05-11T05:04:10.588Z', '2026-05-11T19:01:48.120Z', 'LEGALES: CARTERA DE CONSUMO. PROMOCIÓN PARA COMPRAS CON LAS TARJETAS VISA DÉBITO DE PERSONAS FÍSICAS QUE ACREDITAN SU JUBILACIÓN EN LOS BANCOS DEL GRUPO MACRO ÚNICAMENTE PARA COMERCIOS QUE ESTÉN HABILITADOS EN VISA EN EL RUBRO ÓPTICAS. VÁLIDA LOS DÍAS MIÉRCOLES DESDE EL  01/03/2026 AL 30/06/2026  . 30% DE DESCUENTO, CON UN TOPE DE DEVOLUCIÓN DE $7.000  POR CUENTA Y POR MES, MONTO ÚNICO A DEVOLVER POR MES CON INDEPENDENCIA DE LA CANTIDAD DE OPERACIONES QUE SE REALICEN. EL DESCUENTO SERÁ ACREDITADO EN LA CUENTA DEL CLIENTE DENTRO DE LOS TREINTA DÍAS HÁBILES DE REALIZADA LA OPERACIÓN. LOS BANCOS DEL GRUPO MACRO NO SE RESPONSABILIZAN POR LOS CUPONES PRESENTADOS FUERA DE TÉRMINO POR LOS COMERCIOS. EL BENEFICIO INCLUYE LOS PAGOS A TRAVÉS DE MODO TANTO DE LA APP MACRO COMO EN LA APP MODO. NO APLICA PARA PAGOS REALIZADOS A TRAVÉS DE AGRUPADORES COMO VIÜMI, MERCADO PAGO/TODO PAGO/PEI Y OTROS . CONSULTE BASES, CONDICIONES Y TODA INFORMACIÓN ADICIONAL EN MACRO.COM.AR , COMUNÍQUESE AL 0810-555-2355 PARA BANCO MACRO, O DIRÍJASE A LA SUCURSAL DEL BANCO MÁS CERCANA A SU DOMICILIO.', NULL, ARRAY[]::TEXT[], 'opticas-jubilados-30pct-macro-mie'),
('cmp0qlqfo00x5tux42kvh2hrv', '30% descuento – PANADERIA BLERI (Selecta)', 'PANADERIA BLERI | Gastronomia', FALSE, NULL, FALSE, NULL, '2026-04-01T00:00:00.000Z', '2026-06-30T00:00:00.000Z', 127, NULL, NULL, NULL, 'cmnulzrnd000oqlkkha2lvzwn', 'cmp0qlpw300x3tux4lbd50nya', 'ACTIVE', 'https://www.macro.com.ar/beneficios?d=Any#42765TC0', NULL, NULL, '2026-05-11T05:04:12.564Z', '2026-05-11T19:01:49.834Z', 'CARTERA DE CONSUMO. PROMOCIÓN VÁLIDA DESDE EL 1 DE ABRIL DE 2026 HASTA EL 30 DE JUNIO DE 2026, TODOS LOS DIAS, CON LAS TARJETAS DE CRÉDITO AMEX BLACK, MC BLACK, VISA BUSINESS Y VISA SIGNATURE DE LOS BANCOS DEL GRUPO MACRO. LA PRESENTE PROMOCIÓN APLICA PARA CONSUMOS DE TIPO PERSONAL/FAMILIAR. EN CASO DE DUDA, EL BANCO SE RESERVA EL DERECHO DE NO ACREDITAR EL MONTO DE LA BONIFICACIÓN HASTA TANTO SEA ACLARADO EL DESTINO DE LOS CONSUMOS. 30% DE DESCUENTO  EN UN PAGO TOPE DE DEVOLUCIÓN 30000 PESOS POR CUENTA POR MES.EL BENEFICIO SERÁ APLICADO DENTRO DE LOS 60 DÍAS DE REALIZADA LA COMPRA, AL CIERRE DEL RESUMEN EN EL CUAL SE REGISTRE LA OPERACIÓN O EN LOS DOS SIGUIENTES. NO ACUMULABLE CON OTRAS PROMOCIONES. NO APLICA PARA PAGOS REALIZADOS A TRAVÉS DE MERCADO PAGO/TODO PAGO Y/O PEI. EL DESCUENTO PROMOCIONADO APLICA SOBRE EL PRECIO CONTADO. (EJEMPLOS REPRESENTATIVOS: COMPRA EN CUOTAS: EN UNA COMPRA CON TARJETA DE CRÉDITO DE $1.200 EN 3 CUOTAS SIN INTERÉS, EL CLIENTE ABONARÁ 3 CUOTAS DE $400 CADA UNA. COMPRA CON DESCUENTO Y EN CUOTAS: CON TARJETA DE CRÉDITO CON 10% DE DESCUENTO Y 3 CUOTAS SIN INTERÉS EN UNA COMPRA DE $1.200, CORRESPONDERÁ 3 CUOTAS DE $400 CADA UNA, Y EL BANCO LE REINTEGRARÁ AL CLIENTE DENTRO DE LOS 60 DÍAS DE REALIZADA LA COMPRA, AL CIERRE DEL RESUMEN EN EL CUAL SE REGISTRE LA OPERACIÓN O EN LOS DOS SIGUIENTES LA SUMA DE $ 120. QUEDA ESTABLECIDO QUE LOS DATOS Y OFERTAS INDICADAS REVISTEN CARÁCTER INFORMATIVO Y EN MODO ALGUNO SUPONEN QUE LOS ESTABLECIMIENTOS, PRODUCTOS Y/O SERVICIOS QUE COMERCIALIZAN O LA CALIDAD DE LOS MISMOS SON PROMOCIONADOS O GARANTIZADOS POR LOS BANCOS DEL GRUPO MACRO, COMO ASÍ TAMPOCO SE RESPONSABILIZAN POR LOS CUPONES PRESENTADOS FUERA DE TÉRMINO POR LOS COMERCIOS. MÁS INFORMACIÓN EN FORMA PREVIA A REALIZAR LA OPERACIÓN AL: 0810-555-2355 PARA BANCO MACRO, 0810-555-7353 PARA CLIENTES MACRO SELECTA,  O EN LA SUCURSAL MÁS CERCANA A SU DOMICILIO', NULL, ARRAY[]::TEXT[], 'panaderia-bleri-30pct-macro'),
